namespace sv_ab3f7fa69dd34354a403b2bde898bb14.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly object _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.Add(new Notification(_nextId++, "Welcome to the app!", DateTime.UtcNow.AddMinutes(-10)));
        _notifications.Add(new Notification(_nextId++, "Your profile was updated.", DateTime.UtcNow.AddMinutes(-5)));
        _notifications.Add(new Notification(_nextId++, "New feature available: dark mode.", DateTime.UtcNow.AddMinutes(-2)));
    }

    /// <summary>
    /// Returns all notifications available at this moment.
    /// </summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    /// <summary>
    /// Returns only notifications newer than the given ID (for polling).
    /// </summary>
    public List<Notification> GetSince(int lastSeenId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > lastSeenId).ToList();
        }
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// Called internally to generate fake data.
    /// </summary>
    public void SimulateIncoming()
    {
        var messages = new[]
        {
            "You have a new follower.",
            "Server maintenance scheduled tonight.",
            "Your export is ready to download.",
            "Reminder: team meeting in 30 minutes.",
            "Security alert: new login detected.",
            "Your subscription renews tomorrow.",
        };

        lock (_lock)
        {
            var msg = messages[(_nextId - 1) % messages.Length];
            _notifications.Add(new Notification(_nextId++, msg, DateTime.UtcNow));
        }
    }
}

@page "/notifications"
@rendermode @(new InteractiveServerRenderMode(prerender: true))
@implements IDisposable
@inject sv_ab3f7fa69dd34354a403b2bde898bb14.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@notifications.Count</span></h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item">
                <strong>@n.Message</strong>
                <small class="text-muted ms-2">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<sv_ab3f7fa69dd34354a403b2bde898bb14.Services.Notification> notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    protected override void OnInitialized()
    {
        // Load initial data — this runs during prerender AND interactive init.
        // The prerendered HTML already contains these, and the interactive render
        // re-uses the same data without an extra fetch because we load from the
        // same singleton service synchronously.
        notifications = NotificationService.GetAll();
        _lastSeenId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires in interactive mode (not during static prerender).
            // This is the safe place to start the polling loop.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(5000, ct).ConfigureAwait(false);

            // Simulate a new notification arriving on the server side
            NotificationService.SimulateIncoming();

            var newer = NotificationService.GetSince(_lastSeenId);
            if (newer.Count > 0)
            {
                notifications.AddRange(newer);
                _lastSeenId = newer.Max(n => n.Id);

                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

